_HTML5_FORM_ENCODING_REPLACEMENTS = {'"': "%22", "\\": "\\\\"}
_HTML5_FORM_ENCODING_REPLACEMENTS.update(
    {chr(c): "%{:02X}".format(c) for c in range(0x1F + 1) if c != 0x1B}
)
_HTML5_FORM_ENCODING_RE = re.compile(
    r"|".join([re.escape(c) for c in _HTML5_FORM_ENCODING_REPLACEMENTS.keys()])
)


def normalize_header_key(
    value: typing.Union[str, bytes],
    lower: bool,
    encoding: typing.Optional[str] = None,
) -> bytes:
    """
    Coerce a header key into raw bytes.

    If `value` is a str, it will be encoded using the provided `encoding`
    (defaulting to ASCII). If `lower` is True the resulting bytes are
    lower-cased (which is useful for header lookups).
    """
    if isinstance(value, bytes):
        bytes_value = value
    else:
        bytes_value = value.encode(encoding or "ascii")

    return bytes_value.lower() if lower else bytes_value


def normalize_header_value(
    value: typing.Union[str, bytes], encoding: typing.Optional[str] = None
) -> bytes:
    """
    Coerce a header value into raw bytes.

    If `value` is a str, it will be encoded using the provided `encoding`
    (defaulting to ASCII).
    """
    if isinstance(value, bytes):
        return value
    return value.encode(encoding or "ascii")


def primitive_value_to_str(value: "PrimitiveData") -> str:
    """
    Convert a primitive Python value to its string representation suitable
    for use in e.g. form fields.

    Booleans become 'true'/'false', None becomes an empty string.
    """
    if value is True:
        return "true"
    elif value is False:
        return "false"
    elif value is None:
        return ""
    return str(value)


def is_known_encoding(encoding: str) -> bool:
    """
    Return True if the given encoding name is a known codec on this system.
    """
    try:
        codecs.lookup(encoding)
    except LookupError:
        return False
    return True


def format_form_param(name: str, value: str) -> bytes:
    """
    Encode a name/value pair according to HTML5 form encoding rules for
    multipart form-data field names/values.

    Characters that require escaping are replaced with their percent-encoded
    equivalents; control characters are also percent-encoded.
    """

    def replacer(match: typing.Match[str]) -> str:
        """Replacement function used by the regex substitution above."""
        return _HTML5_FORM_ENCODING_REPLACEMENTS[match.group(0)]

    value = _HTML5_FORM_ENCODING_RE.sub(replacer, value)
    return f'{name}="{value}"'.encode()


def get_ca_bundle_from_env() -> typing.Optional[str]:
    """
    Return the path to a CA bundle based on environment variables.

    Checks SSL_CERT_FILE and SSL_CERT_DIR in the environment and returns the
    first path that exists (file or directory as appropriate). Returns None
    if no environment variables point to existing paths.
    """
    if "SSL_CERT_FILE" in os.environ:
        ssl_file = Path(os.environ["SSL_CERT_FILE"])
        if ssl_file.is_file():
            return str(ssl_file)
    if "SSL_CERT_DIR" in os.environ:
        ssl_path = Path(os.environ["SSL_CERT_DIR"])
        if ssl_path.is_dir():
            return str(ssl_path)
    return None


def parse_header_links(value: str) -> typing.List[typing.Dict[str, str]]:
    """
    Returns a list of parsed link headers.

    For details about the Link header format see:
    https://developer.mozilla.org/en-US/docs/Web/HTTP/Headers/Link
    """
    links: typing.List[typing.Dict[str, str]] = []
    replace_chars = " '\""
    value = value.strip(replace_chars)
    if not value:
        return links
    for val in re.split(", *<", value):
        try:
            url, params = val.split(";", 1)
        except ValueError:
            url, params = val, ""
        link = {"url": url.strip("<> '\"")}
        for param in params.split(";"):
            try:
                key, value = param.split("=")
            except ValueError:
                break
            link[key.strip(replace_chars)] = value.strip(replace_chars)
        links.append(link)
    return links


def parse_content_type_charset(content_type: str) -> typing.Optional[str]:
    """
    Parse the charset parameter from a Content-Type header value.

    Returns the charset as a string if present and known on this platform,
    otherwise returns None.
    """
    if not content_type:
        return None
    parts = [p.strip() for p in content_type.split(";")]
    # Skip the media type portion at parts[0]
    for part in parts[1:]:
        if "=" not in part:
            continue
        key, val = part.split("=", 1)
        if key.strip().lower() == "charset":
            charset = val.strip().strip('"').strip("'")
            return charset if is_known_encoding(charset) else None
    return None


def obfuscate_sensitive_headers(
    headers: typing.Iterable[typing.Tuple[str, str]],
    sensitive_names: typing.Optional[typing.Iterable[str]] = None,
) -> typing.List[typing.Tuple[str, str]]:
    """
    Return a list of headers where sensitive header values have been obfuscated.

    By default this will obfuscate the `authorization` and
    `proxy-authorization` headers (case-insensitive). A custom iterable of
    header names may be supplied via `sensitive_names`.
    """
    if sensitive_names is None:
        sensitive = {"authorization", "proxy-authorization"}
    else:
        sensitive = {n.lower() for n in sensitive_names}

    result: typing.List[typing.Tuple[str, str]] = []
    for name, value in headers:
        if name.lower() in sensitive:
            result.append((name, "*****"))
        else:
            result.append((name, value))
    return result


def port_or_default(url: "URL") -> int:
    """
    Return the port for a URL-like object, using scheme defaults when the
    explicit port is not set.

    The URL object is expected to have `.scheme` and `.port` attributes.
    """
    if getattr(url, "port", None) is not None:
        return url.port
    scheme = getattr(url, "scheme", "").lower()
    return 443 if scheme == "https" else 80


def to_bytes(value: typing.Union[str, bytes], encoding: str = "utf-8") -> bytes:
    """
    Convert a string to bytes using the given encoding, or return bytes unchanged.
    """
    if isinstance(value, bytes):
        return value
    return value.encode(encoding)


def to_str(value: typing.Union[str, bytes], encoding: str = "utf-8") -> str:
    """
    Convert bytes to a string using the given encoding, or return str unchanged.
    """
    if isinstance(value, str):
        return value
    return value.decode(encoding)


def to_bytes_or_str(value: typing.Union[str, bytes], encoding: str = "utf-8") -> typing.Union[str, bytes]:
    """
    Return the value as-is, ensuring it's either a str or bytes.

    This helper simply normalizes bytes/str conversions using the supplied
    encoding, returning the same type as given (i.e., bytes stay bytes,
    str stay str).
    """
    if isinstance(value, bytes):
        return value
    return str(value)


def unquote(value: str, plus_is_space: bool = False) -> str:
    """
    Unquote a percent-encoded string.

    If plus_is_space is True, '+' characters are treated as spaces (like in
    application/x-www-form-urlencoded decoding).
    """
    if plus_is_space:
        return _urllib_unquote_plus(value)
    return _urllib_unquote(value)


def guess_content_type(path: typing.Union[str, Path]) -> str:
    """
    Guess the MIME type for a file path. Falls back to 'application/octet-stream'
    when a type cannot be determined.
    """
    if isinstance(path, Path):
        path = str(path)
    content_type, _ = mimetypes.guess_type(path)
    return content_type or "application/octet-stream"


def is_ipv4_hostname(hostname: str) -> bool:
    """
    Return True if the given hostname is a valid IPv4 address.
    """
    # Remove trailing port if present.
    if ":" in hostname and "[" not in hostname:
        try:
            host_only, port = hostname.split(":", 1)
        except ValueError:
            host_only = hostname
    else:
        host_only = hostname
    try:
        ipaddress.IPv4Address(host_only)
        return True
    except Exception:
        return False


def is_ipv6_hostname(hostname: str) -> bool:
    """
    Return True if the given hostname is a valid IPv6 address.

    IPv6 addresses in URLs are typically enclosed in square brackets;
    this is taken into account.
    """
    # Strip square brackets if present
    host = hostname
    if host.startswith("[") and host.endswith("]"):
        host = host[1:-1]
    # Remove the port if present (after the closing bracket or last colon for plain IPv6)
    if "%" in host:
        # keep zone id intact for parsing in ipaddress
        pass
    try:
        ipaddress.IPv6Address(host)
        return True
    except Exception:
        return False


def sync_start() -> float:
    """
    Return a monotonic timestamp for synchronous code timing.

    This can be used as a start marker for measuring elapsed time.
    """
    return time.monotonic()


def sync_elapsed(start: float) -> float:
    """
    Return the number of seconds elapsed since `start`, where `start` is a
    value previously returned by sync_start().
    """
    return time.monotonic() - start


class Origin:
    """
    Represents the origin of a URL, defined by scheme, host and port.

    Provides comparison and hashing so it can be used as keys in mappings.
    """

    def __init__(self, scheme: str, host: str, port: typing.Optional[int] = None) -> None:
        """
        Create an Origin object.

        Parameters:
            scheme: URL scheme (e.g., 'http' or 'https').
            host: Hostname or IP address.
            port: Optional port number. If omitted, defaults are not applied here.
        """
        self.scheme = scheme.lower()
        self.host = host
        self.port = port

    def matches(self, other: typing.Union["Origin", "URL"]) -> bool:
        """
        Return True if this origin matches another Origin-like object.

        Comparison is done on scheme, normalized host (case-insensitive for
        hostnames) and port. If the other object is a URL-like object it is
        expected to have `.scheme`, `.host` and `.port` attributes.
        """
        if isinstance(other, Origin):
            return (
                self.scheme == other.scheme
                and self.host.lower() == other.host.lower()
                and self.port == other.port
            )
        # Assume a URL-like object with attributes
        other_scheme = getattr(other, "scheme", "").lower()
        other_host = getattr(other, "host", "").lower()
        other_port = getattr(other, "port", None)
        return self.scheme == other_scheme and self.host.lower() == other_host and self.port == other_port

    def __hash__(self) -> int:
        """
        Return a hash value for the origin so it can be used in sets and dicts.
        """
        return hash((self.scheme, self.host.lower(), self.port))

    def __lt__(self, other: "Origin") -> bool:
        """
        Define a consistent ordering for Origin objects to allow sorting.

        Ordering is by scheme, then host (case-insensitive), then port.
        """
        if self.scheme != other.scheme:
            return self.scheme < other.scheme
        if self.host.lower() != other.host.lower():
            return self.host.lower() < other.host.lower()
        # Treat None as less than any integer port
        a_port = -1 if self.port is None else self.port
        b_port = -1 if other.port is None else other.port
        return a_port < b_port

    def __eq__(self, other: object) -> bool:
        """
        Return True if two Origin objects are equal.
        """
        if not isinstance(other, Origin):
            return NotImplemented
        return (
            self.scheme == other.scheme
            and self.host.lower() == other.host.lower()
            and self.port == other.port
        )